  hw.hierpath private @__lowerLayers_path_GCDe1_Verification_Assert_1 [@GCDe1::@sym_0]
  hw.hierpath private @__lowerLayers_path_GCDe1_Verification_Assert_2 [@GCDe1::@sym_1]
  hw.module private @GCDe1_Verification_Assert() attributes {output_file = #hw.output_file<"verification/assert/">} {
    %c0_i20 = hw.constant 0 : i20
    %0 = sv.xmr.ref @__lowerLayers_path_GCDe1_Verification_Assert_2 : !hw.inout<i1>
    %1 = sv.read_inout %0 : !hw.inout<i1>
    %2 = sv.xmr.ref @__lowerLayers_path_GCDe1_Verification_Assert_1 : !hw.inout<i1>
    %3 = sv.read_inout %2 : !hw.inout<i1>
    %4 = sv.xmr.ref @__lowerLayers_path_GCDe1_Verification_Assert_0 : !hw.inout<i20>
    %5 = sv.read_inout %4 : !hw.inout<i20>
    %6 = comb.icmp bin eq %5, %c0_i20 : i20
    %7 = verif.has_been_reset %3, sync %1 {sv.namehint = "has_been_reset"}
    verif.clocked_assert %6 if %7, posedge %3 : i1
    hw.output
  }
  hw.module private @GCDe1_Verification() attributes {output_file = #hw.output_file<"verification/">} {
    hw.output
  }
  hw.module @GCDe1(in %clock : !seq.clock {hw.exportPort = #hw<innerSym@sym_0>}, in %reset : i1 {hw.exportPort = #hw<innerSym@sym_1>}, in %io_value1 : i16, out io_outputGCD : i20) {
    %io_outputGCD = hw.wire %2 sym @sym  : i20
    %0 = comb.extract %io_value1 from 15 {sv.namehint = "io_outputGCD_signBit"} : (i16) -> i1
    %1 = comb.replicate %0 : (i1) -> i4
    %2 = comb.concat %1, %io_value1 {sv.namehint = "io_outputGCD"} : i4, i16
    hw.instance "verification_assert" sym @verification_assert @GCDe1_Verification_Assert() -> () {doNotPrint}
    hw.instance "verification" sym @verification @GCDe1_Verification() -> () {doNotPrint}
    hw.output %2 : i20
  }
  sv.macro.decl @layers_GCDe1_Verification["layers_GCDe1_Verification"]
  emit.file "verification/layers-GCDe1-Verification.sv" {
    sv.ifdef  @layers_GCDe1_Verification {
    } else {
      sv.macro.def @layers_GCDe1_Verification ""
      sv.bind <@GCDe1::@verification>
    }
  }
  sv.macro.decl @layers_GCDe1_Verification_Assert["layers_GCDe1_Verification_Assert"]
  emit.file "verification/assert/layers-GCDe1-Verification-Assert.sv" {
    sv.ifdef  @layers_GCDe1_Verification_Assert {
    } else {
      sv.macro.def @layers_GCDe1_Verification_Assert ""
      sv.include  local "layers-GCDe1-Verification.sv"
      sv.bind <@GCDe1::@verification_assert>
    }
  }
  sv.macro.decl @layers_GCDe1_Verification_Assume["layers_GCDe1_Verification_Assume"]
  emit.file "verification/assume/layers-GCDe1-Verification-Assume.sv" {
    sv.ifdef  @layers_GCDe1_Verification_Assume {
    } else {
      sv.macro.def @layers_GCDe1_Verification_Assume ""
      sv.include  local "layers-GCDe1-Verification.sv"
    }
  }
  sv.macro.decl @layers_GCDe1_Verification_Cover["layers_GCDe1_Verification_Cover"]
  emit.file "verification/cover/layers-GCDe1-Verification-Cover.sv" {
    sv.ifdef  @layers_GCDe1_Verification_Cover {
    } else {
      sv.macro.def @layers_GCDe1_Verification_Cover ""
      sv.include  local "layers-GCDe1-Verification.sv"
    }
  }
  om.class @GCDe1_Class(%basepath: !om.basepath) {
    om.class.fields 
  }
}
